SELECT "FEATURE_NAME", diff FROM (SELECT "FEATURE_NAME", AVG(CASE WHEN "SEX" = 'female' THEN "X_VALUE" END) AS avg_female, AVG(CASE WHEN "SEX" = 'male' THEN "X_VALUE" END) AS avg_male, avg_female - avg_male AS diff FROM "HTAN_2"."HTAN"."SCRNASEQ_MSK_SCLC_COMBINED_SAMPLES_CURRENT" WHERE "CELL_TYPE_GENERAL" = 'Epithelial' AND "CLUSTERS" = '41' AND "DEVELOPMENT_STAGE" = '74-year-old human stage' GROUP BY "FEATURE_NAME" HAVING COUNT(CASE WHEN "SEX" = 'female' AND "X_VALUE" IS NOT NULL THEN 1 END) > 0 AND COUNT(CASE WHEN "SEX" = 'male' AND "X_VALUE" IS NOT NULL THEN 1 END) > 0) ORDER BY ABS(diff) DESC LIMIT 20